const j = $input.first().json;
let body = j.content !== undefined ? j.content : j;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch (e) {} }
return [{ json: body }];

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const b64 = buf.toString('base64');
const ev = $('Leer tarea').item.json;
const prompt = 'Sos control de calidad de una embotelladora (latas). Analiza la foto y devolve SOLO un JSON valido con estas claves:
- tipo_foto: "tapa" | "fondo_impresion" | "pantalla_contador" | "frente" | "otro" (tapa de lata, impresion del fondo de la lata, pantalla/tablero de la maquina con contadores, frente de la lata, u otra cosa)
- contadores: array de numeros leidos (solo si es pantalla_contador; sino [])
- hora_pantalla: hora y/o fecha visible EN la pantalla fotografiada, como string (solo pantalla_contador; sino null)
- textos: array de strings con TODO texto impreso legible (ej lote "L:117 13:55", vencimiento "V:24/10/26")
- etiquetas: array de etiquetas/marcas visibles
- calidad_impresion: "buena" | "mala" | null (solo fondo_impresion: evalua nitidez, legibilidad y completitud de la impresion AUNQUE el dato sea correcto)
- defectos: array con cualquiera de: impresion, centrado, inclinacion, deformacion, etiqueta, contraetiqueta
- resultado: "OK" | "No OK"
- confianza: numero 0..1
Formatos tipicos impresos en el fondo de lata: "L:<lote> <hh:mm>" con "V:<dd/mm/aa>", o "LOTE:<codigo>" con "VTO <dd/mm/aa>" — transcribi EXACTAMENTE lo impreso, sin corregirlo ni completarlo. Si la impresion esta tenue, desgastada, incompleta o dudosa de leer, reduci la confianza por debajo de 0.85 y considera calidad_impresion="mala". Sin texto fuera del JSON.';
const body = { model: 'gpt-4o', max_tokens: 1024, response_format: { type: 'json_object' }, messages: [{ role: 'user', content: [{ type: 'text', text: prompt }, { type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' + b64 } }] }] };
return [{ json: { ...ev, visionBody: body } }];

const resp = $input.first().json;
const ev = $('Leer tarea').item.json;
let raw = '';
try { raw = resp.choices[0].message.content; } catch (e) { raw = ''; }
let parsed = {};
try { const mt = raw.match(/\{[\s\S]*\}/); parsed = JSON.parse(mt ? mt[0] : raw); } catch (e) { parsed = { _parse_error: true }; }
const tokens = (resp.usage && resp.usage.total_tokens) || 0;
let umbral = 0.85;
try { const cfg = $('Leer config').all().map(i => i.json); const u = cfg.find(x => x && x.clave === 'umbral_confianza'); if (u && !isNaN(parseFloat(u.valor))) umbral = parseFloat(u.valor); } catch (e) {}
const confianza = Number(parsed.confianza ?? 0);
const revision_manual = !(confianza >= umbral);
const resultado = revision_manual ? null : (parsed.resultado ?? null);
const calidad_impresion = parsed.calidad_impresion ?? null;
const requiere_atencion = revision_manual || resultado === 'No OK' || calidad_impresion === 'mala';
const motivo = calidad_impresion === 'mala' ? 'calidad de impresion mala' : null;
const estado = revision_manual ? 'revision_manual' : 'procesado';
return [{ json: { evidence_id: ev.evidence_id, proceso: ev.proceso, linea: ev.linea, equipo: ev.equipo, capturado_en: ev.capturado_en, imagen_ref: ev.imagen_ref, tipo_foto: parsed.tipo_foto ?? 'otro', contadores: parsed.contadores ?? [], textos: parsed.textos ?? [], etiquetas: parsed.etiquetas ?? [], hora_pantalla: parsed.hora_pantalla ?? null, calidad_impresion, defectos: parsed.defectos ?? [], resultado, confianza, revision_manual, requiere_atencion, motivo, estado, modelo: (resp.model || 'gpt-4o'), tokens, evaluado_en: new Date().toISOString() } }];

const r = $('Parsear resultado').first().json;
let coherencia = null;
let motivo = r.motivo || null;
if (r.tipo_foto === 'fondo_impresion') {
  const rows = $input.all().map(i => i.json).filter(j => j && j.cont_evidence_id);
  if (rows.length) {
    const reHora = /([01]?\d|2[0-3]):[0-5]\d/g;
    const lataAll = (r.textos || []).join(' ').toUpperCase();
    let contTextos = rows[0].cont_textos || [];
    if (typeof contTextos === 'string') { try { contTextos = JSON.parse(contTextos); } catch (e) { contTextos = [contTextos]; } }
    const contAll = (Array.isArray(contTextos) ? contTextos : [String(contTextos)]).join(' ').toUpperCase();
    const fallas = [];
    let checks = 0;
    // 1) LOTE: formato corto "L:117" o largo "LOTE:10010-5A" vs pantalla "LOTE...: xxx"
    const mLoteLargo = lataAll.match(/LOTE\s*[:\.]?\s*([0-9A-Z][0-9A-Z-]{2,})/);
    const mLoteCorto = lataAll.match(/L\s*[:\.]\s*([0-9]{2,6})/);
    const lataLote = (mLoteLargo || mLoteCorto || [])[1] || null;
    const contLote = (contAll.match(/LOTE[^:]{0,25}:\s*([0-9A-Z][0-9A-Z-]*)/) || [])[1] || null;
    if (lataLote && contLote) {
      checks++;
      const a = lataLote.replace(/^0+/, '');
      const b = contLote.replace(/^0+/, '');
      if (a !== b && !b.split('-').includes(a) && !a.split('-').includes(b)) fallas.push('lote impreso ' + lataLote + ' distinto del lote en pantalla ' + contLote);
    }
    // 2) VTO: "V:24/10/26" o "VTO 29/03/27" vs pantalla "VTO/VENC...: dd/mm/aa"
    const norm = s => s.replace(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/, (m, d, mo, y) => ('' + d).padStart(2, '0') + '/' + ('' + mo).padStart(2, '0') + '/' + ('' + y).slice(-2));
    const lataVto = (lataAll.match(/V(?:TO)?\.?\s*[:\.]?\s*(\d{1,2}\/\d{1,2}\/\d{2,4})/) || [])[1] || null;
    const contVto = (contAll.match(/(?:VTO|VENC)[^:]{0,25}:\s*(\d{1,2}\/\d{1,2}\/\d{2,4})/) || [])[1] || null;
    if (lataVto && contVto) {
      checks++;
      if (norm(lataVto) !== norm(contVto)) fallas.push('vencimiento impreso ' + lataVto + ' distinto del de pantalla ' + contVto);
    }
    // 3) HORA impresa vs hora en pantalla (tolerancia 90 min)
    const horasLata = lataAll.match(reHora) || [];
    const horasPant = ((rows[0].cont_hora_pantalla || '').toString().match(reHora)) || [];
    if (horasLata.length && horasPant.length) {
      checks++;
      const toMin = s => { const p = s.split(':').map(Number); return p[0] * 60 + p[1]; };
      let diff = Infinity;
      for (const hl of horasLata) { for (const hp of horasPant) { let d = Math.abs(toMin(hl) - toMin(hp)); d = Math.min(d, 1440 - d); if (d < diff) diff = d; } }
      if (diff > 90) fallas.push('hora impresa (' + horasLata.join(',') + ') lejos de la pantalla (' + horasPant.join(',') + '), dif ' + diff + ' min');
    }
    if (checks > 0) {
      coherencia = fallas.length === 0;
      if (fallas.length) motivo = fallas.join(' | ');
    }
  }
}
const requiere_atencion = r.requiere_atencion || coherencia === false;
const resultado = coherencia === false ? 'No OK' : r.resultado;
return [{ json: { ...r, coherencia, motivo, resultado, requiere_atencion } }];

